import type { CardConfig } from "../contracts/types";

export type SavedConfigSecurityFieldHook = (config: CardConfig) => void;
export type SavedConfigSecurityOptionHook = (options: string, config: CardConfig) => string;

export function normalizeSavedConfigSecurity(
  config: CardConfig,
  normalizeFields: SavedConfigSecurityFieldHook,
  normalizeOptions: SavedConfigSecurityOptionHook,
): boolean {
  if (config.type === "alarm") {
    normalizeFields(config);
    config.icon_on = "Auto";
    config.sensor = "";
    config.unit = "";
    config.type = "alarm";
    config.precision = "";
    config.options = normalizeOptions(config.options || "", config);
    return true;
  }
  if (config.type === "alarm_action") {
    normalizeFields(config);
    config.icon_on = "Auto";
    config.unit = "";
    config.type = "alarm_action";
    config.precision = "";
    config.options = normalizeOptions(config.options || "", config);
    return true;
  }
  return false;
}
